-- Migração v25 — Portal Britto Laticínios
-- Como usar: Supabase → SQL Editor → cole este arquivo inteiro → Run.
-- Pode rodar mais de uma vez sem problema (upserts idempotentes).

-- 1) Colunas novas
alter table industrias add column if not exists pecas_por_caixa integer;
alter table industrias add column if not exists kg_por_peca_aprox numeric;
alter table industrias add column if not exists kg_por_pallet_aprox numeric;
alter table produtos add column if not exists unidade_venda text;

