-- 4) Remove os produtos descontinuados na v25 (queijos fatiados/minas/requeijão).
-- Se der erro de chave estrangeira (algum pedido antigo usa esses produtos), apague
-- apenas as linhas de precos_cliente e deixe os produtos com preço zero em vez de removê-los.
delete from precos_cliente where produto_id in ('p4', 'p5', 'p6', 'p7');
delete from produtos where id in ('p4', 'p5', 'p6', 'p7');

